query:
-- Remover duplicados: manter o menor ID para cada nome duplicado
DELETE FROM players WHERE id IN (
  SELECT id FROM (
    SELECT id, name,
      ROW_NUMBER() OVER (PARTITION BY name ORDER BY 
        CASE WHEN imageUrl IS NOT NULL AND imageUrl != '' THEN 0 ELSE 1 END,
        id ASC
      ) as rn
    FROM players
    WHERE name IN (
      SELECT name FROM players GROUP BY name HAVING COUNT(*) > 1
    )
  ) ranked
  WHERE rn > 1
);

